import { DBRecord } from '../types';

const STORE = '360digi_v2';

function getDB(): Record<string, Record<string, DBRecord[]>> {
  try {
    return JSON.parse(localStorage.getItem(STORE) || '{}');
  } catch {
    return {};
  }
}

function saveDB(db: Record<string, Record<string, DBRecord[]>>): void {
  localStorage.setItem(STORE, JSON.stringify(db));
}

function todayKey(): string {
  return new Date().toISOString().split('T')[0];
}

export function saveRecord<T extends Record<string, unknown>>(folder: string, data: T): T & DBRecord {
  const db = getDB();
  const d = todayKey();
  if (!db[d]) db[d] = {};
  if (!db[d][folder]) db[d][folder] = [];
  const record = {
    ...data,
    _id: 'r_' + Date.now(),
    _timestamp: new Date().toISOString(),
    _date: d,
  } as T & DBRecord;
  db[d][folder].push(record as DBRecord);
  saveDB(db);
  return record;
}

export function getAllRecords(folder: string): DBRecord[] {
  const db = getDB();
  const all: DBRecord[] = [];
  Object.keys(db)
    .sort((a, b) => b.localeCompare(a))
    .forEach(date => {
      (db[date][folder] || []).forEach(r => all.push(r));
    });
  return all;
}

export function getFullDB(): Record<string, Record<string, DBRecord[]>> {
  return getDB();
}

export function clearDB(): void {
  localStorage.removeItem(STORE);
}

export function fmtDate(iso?: string): string {
  if (!iso) return '—';
  const d = new Date(iso);
  return (
    d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }) +
    ' ' +
    d.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' })
  );
}

export function exportJSON(data: unknown, filename: string): void {
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = filename;
  a.click();
  URL.revokeObjectURL(a.href);
}
