import React, { useState } from 'react';
import { NavLink, Link } from 'react-router-dom';

const Navbar: React.FC = () => {
  const [open, setOpen] = useState(false);

  const linkClass = ({ isActive }: { isActive: boolean }) =>
    isActive ? 'active' : '';

  return (
    <>
      <nav className="navbar">
        <div className="navbar-inner">
          <Link to="/" className="nav-logo">
            <div className="logo-mark">360</div>
            <span className="logo-text">
              <span className="digi">Digi</span>
              <span className="learning">Learning</span>
            </span>
          </Link>
          <div className="nav-links">
            <NavLink to="/" className={linkClass} end>Home</NavLink>
            <NavLink to="/programs" className={linkClass}>Programs</NavLink>
            <NavLink to="/practice-exam" className={linkClass}>Practice Exam</NavLink>
            <NavLink to="/training" className={linkClass}>Training</NavLink>
            <NavLink to="/request" className={linkClass}>Request Session</NavLink>
            <NavLink to="/login" className={linkClass}>Login</NavLink>
            <Link to="/request" className="btn-nav-cta">Get Started</Link>
          </div>
          <button
            className="hamburger"
            aria-label="Menu"
            onClick={() => setOpen(!open)}
          >
            <span /><span /><span />
          </button>
        </div>
      </nav>
      <div className={`mobile-menu${open ? ' open' : ''}`}>
        <NavLink to="/" end onClick={() => setOpen(false)}>Home</NavLink>
        <NavLink to="/programs" onClick={() => setOpen(false)}>Programs</NavLink>
        <NavLink to="/practice-exam" onClick={() => setOpen(false)}>Practice Exam</NavLink>
        <NavLink to="/training" onClick={() => setOpen(false)}>Training</NavLink>
        <NavLink to="/request" onClick={() => setOpen(false)}>Request Session</NavLink>
        <NavLink to="/login" onClick={() => setOpen(false)}>Login</NavLink>
        <Link to="/admin-login" style={{ color: 'var(--gray-400)' }} onClick={() => setOpen(false)}>Admin</Link>
      </div>
    </>
  );
};

export default Navbar;
